const leads = $input.all()[0]?.json?.data || [];
const sent = $input.all()[1]?.json?.data || [];
const followup = $input.all()[2]?.json?.data || [];

const statuses = {NEW: 0, CONTACTED: 0, OPENED: 0, CLICKED: 0, REPLIED: 0, MEETING: 0, WON: 0, LOST: 0};

for (const l of leads) {
  const s = (l.status || '').toUpperCase();
  if (statuses.hasOwnProperty(s)) statuses[s]++;
  else statuses.NEW++;
}

const total = leads.length || 1;
const funnel = [
  {stage: 'Leads', count: total, pct: 100},
  {stage: 'Contacted', count: statuses.CONTACTED + sent.length, pct: Math.round((sent.length/total)*100)},
  {stage: 'Replied', count: statuses.REPLIED, pct: Math.round((statuses.REPLIED/total)*100)},
  {stage: 'Meeting', count: statuses.MEETING, pct: Math.round((statuses.MEETING/total)*100)},
  {stage: 'Won', count: statuses.WON, pct: Math.round((statuses.WON/total)*100)}
];

return {campaign: {total, statuses, funnel, followups: followup.length, activeRate: Math.round(((sent.length + followup.length)/total)*100)}, generatedAt: new Date().toISOString()};
